final class DemoPaymentViewController: UIViewController, STPPaymentCardTextFieldDelegate {
    var onStatusUpdate: ((String) -> Void)?

    private let cardField = STPPaymentCardTextField()
    private let payButton = UIButton(type: .system)
    private let titleLabel = UILabel()
    private let subtitleLabel = UILabel()
    private let amountLabel = UILabel()

    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .systemBackground

        titleLabel.text = "Complete Demo Payment"
        titleLabel.font = .boldSystemFont(ofSize: 24)
        titleLabel.textAlignment = .center

        subtitleLabel.text = "Enter a Stripe test card to simulate checkout."
        subtitleLabel.font = .systemFont(ofSize: 14)
        subtitleLabel.textColor = .secondaryLabel
        subtitleLabel.textAlignment = .center
        subtitleLabel.numberOfLines = 0

        amountLabel.text = "Charge Amount: $19.99"
        amountLabel.font = .systemFont(ofSize: 18, weight: .semibold)
        amountLabel.textAlignment = .center

        cardField.delegate = self
        cardField.postalCodeEntryEnabled = true

        payButton.setTitle("Pay $19.99", for: .normal)
        payButton.titleLabel?.font = .boldSystemFont(ofSize: 18)
        payButton.backgroundColor = .systemBlue
        payButton.tintColor = .white
        payButton.layer.cornerRadius = 12
        payButton.contentEdgeInsets = UIEdgeInsets(top: 14, left: 20, bottom: 14, right: 20)
        payButton.addTarget(self, action: #selector(handlePayment), for: .touchUpInside)

        let stack = UIStackView(arrangedSubviews: [titleLabel, subtitleLabel, amountLabel, cardField, payButton])
        stack.axis = .vertical
        stack.spacing = 20
        stack.translatesAutoresizingMaskIntoConstraints = false

        view.addSubview(stack)

        NSLayoutConstraint.activate([
            stack.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 24),
            stack.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -24),
            stack.centerYAnchor.constraint(equalTo: view.centerYAnchor),
            cardField.heightAnchor.constraint(equalToConstant: 50)
        ])
    }

    @objc private func handlePayment() {
        guard cardField.isValid else {
            onStatusUpdate?("Invalid card details")
            showAlert(title: "Invalid Card", message: "Please enter a valid Stripe test card.")
            return
        }

        payButton.isEnabled = false
        payButton.alpha = 0.7
        onStatusUpdate?("Processing demo payment...")

        let cardParams = cardField.cardParams
        let paymentMethodParams = STPPaymentMethodParams(card: cardParams, billingDetails: nil, metadata: nil)

        STPAPIClient.shared.createPaymentMethod(with: paymentMethodParams) { [weak self] paymentMethod, error in
            DispatchQueue.main.async {
                guard let self = self else { return }

                self.payButton.isEnabled = true
                self.payButton.alpha = 1.0

                if let error = error {
                    self.onStatusUpdate?("Payment failed")
                    self.showAlert(title: "Demo Failed", message: error.localizedDescription)
                    return
                }

                if let paymentMethod = paymentMethod {
                    self.onStatusUpdate?("Demo payment succeeded")
                    self.showAlert(
                        title: "Demo Success",
                        message: "Created PaymentMethod: \(paymentMethod.stripeId)\n\nThis confirms Stripe SDK integration for investor demo purposes."
                    )
                } else {
                    self.onStatusUpdate?("Unknown payment result")
                    self.showAlert(title: "Unknown Result", message: "No payment method was returned.")
                }
            }
        }
    }

    func paymentCardTextFieldDidChange(_ textField: STPPaymentCardTextField) {
        payButton.isEnabled = textField.isValid
        payButton.alpha = textField.isValid ? 1.0 : 0.6
    }

    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Done", style: .default))
        present(alert, animated: true)
    }
}